// Smart Analyzer v3
// Analysis-only node: inspects streams, makes routing decisions, stores results in args.variables.
// Does NOT run ffmpeg. Downstream executor nodes consume the variables.
//
// Output routing:
//   1 = File already perfect (skip)
//   2 = Audio needs work, video is fine (audio-only executor)
//   3 = Video needs re-encoding too (AV executor)
//   4 = Error (no video, no audio, ffprobe failed)

// === MODULE-LEVEL CONSTANTS ===

const ALLOWED_LANGUAGES = ['eng', 'jpn', 'kor', 'fre'];

const languagePatterns = {
  eng: [
    /\benglish\b/i, /\beng\b/i, /\ben\b/i, /\ben[-_]us\b/i, /\ben[-_]gb\b/i,
    /\ben[-_]au\b/i, /\ben[-_]ca\b/i, /\benglish\s+audio\b/i
  ],
  jpn: [
    /\bjapanese\b/i, /\bjpn\b/i, /\bja\b/i, /\bja[-_]jp\b/i,
    /\bnihongo\b/i, /\b日本語\b/i, /\bjapanese\s+audio\b/i
  ],
  kor: [
    /\bkorean\b/i, /\bkor\b/i, /\bko\b/i, /\bko[-_]kr\b/i,
    /\bhangul\b/i, /\b한국어\b/i, /\bkorean\s+audio\b/i
  ],
  fre: [
    /\bfrench\b/i, /\bfre\b/i, /\bfr\b/i, /\bfr[-_]fr\b/i,
    /\bfrancais\b/i, /\bfrançais\b/i, /\bfrench\s+audio\b/i
  ]
};

const commentaryPatterns = [
  /commentary/i, /director.?s?\s+commentary/i, /cast\s+commentary/i,
  /production.*commentary/i, /design.*commentary/i, /audio\s+commentary/i,
  /filmmaker.*commentary/i, /writer.*commentary/i, /producer.*commentary/i,
  /behind.*scenes/i, /making.*of/i, /^commentary$/i, /\bcomm\b/i,
  /director.*track/i, /bonus.*audio/i, /audio\s+description/i,
  /descriptive\s+audio/i, /described\s+video/i, /\bad\b/i,
  /vision.*impaired/i, /accessibility/i
];

const BITMAP_SUBTITLE_CODECS = ['hdmv_pgs_subtitle', 'dvd_subtitle', 'dvb_subtitle'];
const CONVERTIBLE_SUBTITLE_CODECS = ['ass', 'ssa', 'webvtt', 'mov_text'];

// Bitrate thresholds (kbps) for determining if video re-encode is needed
const VIDEO_BITRATE_THRESHOLDS = {
  '720p_and_below': 3000,
  '1080p': 5000
};

// === HELPER FUNCTIONS ===

function detectLanguage(stream) {
  const title = (stream.tags?.title || '').toLowerCase();
  const language = (stream.tags?.language || '').toLowerCase();

  const textToCheck = `${title} ${language}`.trim();
  if (commentaryPatterns.some(p => p.test(textToCheck))) return 'commentary';

  if (['eng', 'en', 'english'].includes(language)) return 'eng';
  if (['jpn', 'ja', 'japanese'].includes(language)) return 'jpn';
  if (['kor', 'ko', 'korean'].includes(language)) return 'kor';
  if (['fre', 'fr', 'french', 'fra'].includes(language)) return 'fre';

  for (const [langCode, patterns] of Object.entries(languagePatterns)) {
    if (title && patterns.some(p => p.test(title))) return langCode;
  }
  for (const [langCode, patterns] of Object.entries(languagePatterns)) {
    if (patterns.some(p => p.test(textToCheck))) return langCode;
  }

  if (title) {
    if (/\b(dub|dubbed)\b/i.test(title) && !/\b(sub|subtitle)\b/i.test(title)) return 'eng';
  }

  return 'unknown';
}

function validateAudioStream(stream, index, args, sourceFile, ffprobePath, ffmpegPath) {
  const codec = stream.codec_name || '';
  const duration = parseFloat(stream.duration) || 0;
  const tags = stream.tags || {};
  const channels = parseInt(stream.channels || '0', 10);
  const sampleRate = parseInt(stream.sample_rate || '0', 10);

  const streamBitRate = parseInt(stream.bit_rate || '0', 10);
  const tagBitRate = parseInt(tags.BPS || tags['BPS-eng'] || '0', 10);
  const frameCount = parseInt(tags.NUMBER_OF_FRAMES || tags['NUMBER_OF_FRAMES-eng'] || '0', 10);
  const byteCount = parseInt(tags.NUMBER_OF_BYTES || tags['NUMBER_OF_BYTES-eng'] || '0', 10);

  const bestBitRate = streamBitRate > 0 ? streamBitRate : tagBitRate;
  const bestChannels = channels;

  if (!codec || codec.trim() === '') {
    args.jobLog(`    -> Validation FAILED: missing codec`);
    return false;
  }
  if (bestChannels === 0) {
    args.jobLog(`    -> Validation FAILED: 0 channels`);
    return false;
  }
  if (bestChannels > 32) {
    args.jobLog(`    -> Validation FAILED: unreasonable channel count (${bestChannels})`);
    return false;
  }
  if (sampleRate > 0 && (sampleRate < 8000 || sampleRate > 192000)) {
    args.jobLog(`    -> Validation FAILED: invalid sample rate (${sampleRate})`);
    return false;
  }
  if (frameCount === 0 && byteCount === 0 && bestBitRate === 0) {
    args.jobLog(`    -> Validation FAILED: completely empty stream`);
    return false;
  }
  if (duration === 0 && frameCount === 0 && byteCount === 0) {
    args.jobLog(`    -> Validation FAILED: 0 duration + 0 frames + 0 bytes`);
    return false;
  }
  if (byteCount > 0 && byteCount < 1000 && frameCount === 0 && duration > 10) {
    args.jobLog(`    -> Validation FAILED: suspiciously small (${byteCount} bytes)`);
    return false;
  }

  // Deep packet-level probe
  try {
    const { execFileSync } = require('child_process');
    const deepProbeResult = execFileSync(ffprobePath, [
      '-v', 'error',
      '-select_streams', `a:${index}`,
      '-show_entries', 'packet=pts,dts,size,flags',
      '-read_intervals', '%+#5',
      '-of', 'csv=p=0',
      sourceFile
    ], { encoding: 'utf8', timeout: 10000 });

    const packets = deepProbeResult.trim().split('\n').filter(l => l.trim());
    if (packets.length === 0) {
      args.jobLog(`    -> Validation FAILED: no audio packets found`);
      return false;
    }

    let corrupted = 0;
    let valid = 0;
    for (const packet of packets) {
      const parts = packet.split(',');
      if (parts.length >= 3) {
        const size = parseInt(parts[2] || '0', 10);
        if (size === 0 || size >= 1000000) corrupted++;
        else valid++;
      }
    }
    if (corrupted > valid) {
      args.jobLog(`    -> Validation FAILED: ${corrupted}/${packets.length} packets corrupted`);
      return false;
    }
  } catch (e) {
    if (frameCount === 0 || byteCount === 0) {
      args.jobLog(`    -> Validation FAILED: cannot probe packets and empty indicators`);
      return false;
    }
  }

  // Muxing compatibility test for problematic codecs
  if (['eac3', 'ac3', 'dts', 'truehd'].includes(codec.toLowerCase())) {
    try {
      const { execFileSync } = require('child_process');
      const path = require('path');
      const fs = require('fs');
      const testFile = path.join(path.dirname(sourceFile), `test_audio_${index}_${Date.now()}.mkv`);

      execFileSync(ffmpegPath, [
        '-v', 'error', '-i', sourceFile,
        '-map', `0:a:${index}`, '-c:a', 'copy',
        '-t', '1', '-f', 'matroska', '-y', testFile
      ], { encoding: 'utf8', timeout: 15000 });

      if (fs.existsSync(testFile)) fs.unlinkSync(testFile);
    } catch (muxErr) {
      const errMsg = muxErr.stderr || muxErr.stdout || muxErr.message || '';
      if (errMsg.includes('Error submitting a packet') || errMsg.includes('Invalid argument') || errMsg.includes('Error muxing')) {
        args.jobLog(`    -> Validation FAILED: muxing test error - ${errMsg.substring(0, 200)}`);
        return false;
      }
    }
  }

  return true;
}

function validateSubtitleStream(stream, index, args, sourceFile, ffprobePath) {
  const codec = stream.codec_name || '';
  const tags = stream.tags || {};
  const duration = parseFloat(stream.duration) || 0;
  const frameCount = parseInt(tags.NUMBER_OF_FRAMES || tags['NUMBER_OF_FRAMES-eng'] || '0', 10);
  const byteCount = parseInt(tags.NUMBER_OF_BYTES || tags['NUMBER_OF_BYTES-eng'] || '0', 10);
  const bitRate = parseInt(tags.BPS || tags['BPS-eng'] || stream.bit_rate || '0', 10);
  const streamDuration = parseFloat(tags.DURATION || tags['DURATION-eng'] || '0');
  const width = parseInt(stream.width || '0', 10);
  const height = parseInt(stream.height || '0', 10);

  if (!codec || codec.trim() === '') {
    args.jobLog(`    -> Sub validation FAILED: missing codec`);
    return false;
  }

  if (BITMAP_SUBTITLE_CODECS.includes(codec)) {
    if (width === 0 && height === 0) {
      args.jobLog(`    -> Sub validation FAILED: bitmap ${codec} unspecified size`);
      return false;
    }
    if ((width === 0) !== (height === 0)) {
      args.jobLog(`    -> Sub validation FAILED: bitmap ${codec} incomplete dimensions`);
      return false;
    }
    if (width > 8192 || height > 8192 || (width > 0 && width < 16) || (height > 0 && height < 16)) {
      args.jobLog(`    -> Sub validation FAILED: bitmap ${codec} unreasonable dimensions (${width}x${height})`);
      return false;
    }
  }

  if (frameCount === 0 && byteCount === 0 && bitRate === 0) {
    args.jobLog(`    -> Sub validation FAILED: completely empty`);
    return false;
  }

  const zeroIndicators = [
    frameCount === 0,
    byteCount === 0,
    bitRate === 0,
    duration === 0 && streamDuration === 0,
    width === 0 && height === 0 && BITMAP_SUBTITLE_CODECS.includes(codec)
  ];
  if (zeroIndicators.filter(Boolean).length >= 3) {
    args.jobLog(`    -> Sub validation FAILED: too many zero indicators`);
    return false;
  }

  if (BITMAP_SUBTITLE_CODECS.includes(codec)) {
    if (frameCount === 0) {
      args.jobLog(`    -> Sub validation FAILED: bitmap ${codec} no frames`);
      return false;
    }
    if (byteCount === 0) {
      args.jobLog(`    -> Sub validation FAILED: bitmap ${codec} no data`);
      return false;
    }
    if (byteCount > 0 && byteCount < 1000 && frameCount < 10) {
      args.jobLog(`    -> Sub validation FAILED: bitmap ${codec} too small`);
      return false;
    }

    // FFprobe dimension validation for bitmap subs
    try {
      const { execFileSync } = require('child_process');
      const probeResult = execFileSync(ffprobePath, [
        '-v', 'error', '-select_streams', `s:${index}`,
        '-show_entries', 'stream=width,height,codec_name',
        '-of', 'csv=p=0', sourceFile
      ], { encoding: 'utf8', timeout: 5000 });

      const parts = probeResult.trim().split(',');
      const pw = parseInt(parts[0] || '0', 10);
      const ph = parseInt(parts[1] || '0', 10);
      if (Number.isNaN(pw) || Number.isNaN(ph) || (pw === 0 && ph === 0)) {
        args.jobLog(`    -> Sub validation FAILED: ffprobe confirms unspecified size`);
        return false;
      }
    } catch (e) {
      if (frameCount === 0 || byteCount === 0) {
        args.jobLog(`    -> Sub validation FAILED: cannot probe and empty indicators`);
        return false;
      }
    }
  }

  if (['subrip', 'ass', 'ssa', 'webvtt', 'mov_text'].includes(codec)) {
    if (byteCount > 0 && byteCount < 50) {
      args.jobLog(`    -> Sub validation FAILED: text sub too small (${byteCount} bytes)`);
      return false;
    }
    if (frameCount === 0 && byteCount === 0) {
      args.jobLog(`    -> Sub validation FAILED: text sub no frames and no data`);
      return false;
    }
  }

  if (byteCount > 0 && byteCount < 100 && frameCount === 0) {
    args.jobLog(`    -> Sub validation FAILED: too small (${byteCount} bytes, 0 frames)`);
    return false;
  }

  return true;
}

function analyzeAVDesync(videoStreams, audioStreams, args) {
  const primaryVideo = videoStreams[0];
  if (!primaryVideo) return { needsOffset: false, reason: 'No video stream', desyncResults: [] };

  const videoStartTime = parseFloat(primaryVideo.start_time || '0');
  const DESYNC_THRESHOLD_MS = 40;

  const desyncResults = audioStreams.map(({ stream, index, lang }) => {
    const audioStartTime = parseFloat(stream.start_time || '0');
    return {
      streamIndex: index,
      audioStartTime,
      desyncOffset: videoStartTime - audioStartTime,
      language: lang || 'unknown'
    };
  });

  const maxAbsOffsetMs = Math.max(0, ...desyncResults.map(r => Math.abs(r.desyncOffset))) * 1000;
  const needsOffset = maxAbsOffsetMs >= DESYNC_THRESHOLD_MS;

  return {
    needsOffset,
    videoStartTime,
    desyncResults,
    maxAbsOffsetMs,
    threshold: DESYNC_THRESHOLD_MS,
    reason: needsOffset
      ? `Max offset ${maxAbsOffsetMs.toFixed(1)}ms exceeds ${DESYNC_THRESHOLD_MS}ms threshold`
      : `Max offset ${maxAbsOffsetMs.toFixed(1)}ms within threshold`
  };
}

function getVideoQualityTier(height) {
  return height > 720 ? '1080p' : '720p_and_below';
}

// === MAIN MODULE ===

module.exports = async (args) => {
  const { execFileSync } = require('child_process');
  const path = require('path');

  args.jobLog('='.repeat(50));
  args.jobLog('   SMART ANALYZER v3');
  args.jobLog('='.repeat(50));

  const inputFile = args.inputFileObj._id || args.inputFileObj.file;
  const fileName = path.basename(inputFile);
  const ext = path.extname(fileName).toLowerCase().replace('.', '');
  const container = (args.inputFileObj.container || '').toLowerCase();
  const isMKV = ext === 'mkv' || container === 'mkv' || container === 'matroska';
  const isMP4 = ext === 'mp4' || container === 'mp4' || ext === 'm4v';
  const isAVI = ext === 'avi' || container === 'avi';

  args.jobLog(`Input: ${inputFile}`);
  args.jobLog(`Container: ${container} (${isMKV ? 'MKV' : isMP4 ? 'MP4' : isAVI ? 'AVI' : 'Unknown'})`);

  if (!isMKV && !isMP4 && !isAVI) {
    args.jobLog('Not MKV/MP4/AVI -- skipping');
    return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
  }

  const ffprobePath = args.deps.ffprobePath || 'ffprobe';
  const ffmpegPath = args.deps.ffmpegPath || 'ffmpeg';

  // Determine source file (respect workDir if provided)
  const fs = require('fs');
  let sourceFile = inputFile;
  if (args.workDir && args.workDir.trim() !== '') {
    const workingFile = path.join(path.normalize(args.workDir), path.basename(inputFile));
    if (fs.existsSync(workingFile)) {
      sourceFile = workingFile;
      args.jobLog(`Using working file: ${sourceFile}`);
    }
  }

  if (!fs.existsSync(sourceFile)) {
    args.jobLog(`ERROR: Source file does not exist: ${sourceFile}`);
    return { outputFileObj: args.inputFileObj, outputNumber: 4, variables: args.variables };
  }

  // ─── STEP 1: FFPROBE ───
  args.jobLog('\n--- FFprobe Analysis ---');
  let mediaInfo;
  try {
    const probeResult = execFileSync(ffprobePath, [
      '-v', 'quiet', '-print_format', 'json',
      '-show_streams', '-show_format', sourceFile
    ], { encoding: 'utf8', maxBuffer: 1024 * 1024 * 10 });
    mediaInfo = JSON.parse(probeResult);
  } catch (e) {
    args.jobLog(`ERROR: ffprobe failed: ${e.message}`);
    return { outputFileObj: args.inputFileObj, outputNumber: 4, variables: args.variables };
  }

  const streams = mediaInfo.streams || [];
  const duration = parseFloat(mediaInfo.format?.duration || '0');
  const overallBitrate = parseInt(mediaInfo.format?.bit_rate || '0', 10);
  args.jobLog(`Found ${streams.length} streams, duration ${duration.toFixed(1)}s, bitrate ${Math.round(overallBitrate / 1000)}kbps`);

  // ─── STEP 2: CLASSIFY STREAMS ───
  const rawVideoStreams = streams.filter(s => s.codec_type === 'video');
  const coverArtStreams = rawVideoStreams.filter(s => s.disposition && s.disposition.attached_pic);
  const videoStreams = rawVideoStreams.filter(s => !(s.disposition && s.disposition.attached_pic));
  const audioStreams = streams.filter(s => s.codec_type === 'audio');
  const subtitleStreams = streams.filter(s => s.codec_type === 'subtitle');

  if (coverArtStreams.length > 0) {
    args.jobLog(`Removing ${coverArtStreams.length} cover-art stream(s)`);
  }

  args.jobLog(`Video: ${videoStreams.length}, Audio: ${audioStreams.length}, Subtitle: ${subtitleStreams.length}`);

  if (videoStreams.length === 0) {
    args.jobLog('ERROR: No video streams found');
    return { outputFileObj: args.inputFileObj, outputNumber: 4, variables: args.variables };
  }

  // ─── STEP 3: VIDEO ANALYSIS ───
  args.jobLog('\n--- Video Analysis ---');
  const primaryVideo = videoStreams[0];
  const videoCodec = (primaryVideo.codec_name || '').toLowerCase();
  const videoHeight = parseInt(primaryVideo.height || '0', 10);
  const videoWidth = parseInt(primaryVideo.width || '0', 10);
  const videoQualityTier = getVideoQualityTier(videoHeight);

  // Calculate video bitrate (overall - audio bitrates)
  let audioBitrateSum = 0;
  audioStreams.forEach(s => {
    audioBitrateSum += parseInt(s.bit_rate || '0', 10);
  });
  const estimatedVideoBitrate = Math.max(0, overallBitrate - audioBitrateSum);
  const estimatedVideoBitrateKbps = Math.round(estimatedVideoBitrate / 1000);

  const isHEVC = videoCodec === 'hevc' || videoCodec === 'h265';
  const bitrateThreshold = VIDEO_BITRATE_THRESHOLDS[videoQualityTier];
  const videoBitrateOk = estimatedVideoBitrateKbps <= bitrateThreshold;
  const needsVideoReencode = !isHEVC || !videoBitrateOk;

  // Determine target resolution for downscaling
  // Only downscale if the source is significantly above the target (>10% taller).
  // This avoids pointless quality loss on files like 1920x800 (cinema 2.4:1) that are
  // technically "above 720p" but close enough to keep as-is.
  let targetResolution = null;
  if (needsVideoReencode) {
    if (videoHeight > 1080) {
      // 4K/1440p: keep original (no scaling)
    } else if (videoHeight > 900) {
      // True 1080p content (>900 lines) — downscale to 720p
      // This preserves cinema crops like 1920x800 (2.4:1) which are 720p-class
      targetResolution = '720p';
    } else if (videoHeight > 600 && videoHeight <= 720) {
      // True 720p content (>600 lines, <=720) — downscale to 480p
      targetResolution = '480p';
    }
    // Otherwise (<=600, or 721-900 like cinema crops): keep original resolution
  }

  args.jobLog(`Video: ${videoCodec} ${videoWidth}x${videoHeight} (~${estimatedVideoBitrateKbps}kbps)`);
  args.jobLog(`Quality tier: ${videoQualityTier}, threshold: ${bitrateThreshold}kbps`);
  args.jobLog(`HEVC: ${isHEVC}, bitrate OK: ${videoBitrateOk}, needs re-encode: ${needsVideoReencode}`);
  if (targetResolution) args.jobLog(`Target resolution: ${targetResolution}`);

  // ─── STEP 4: AUDIO ANALYSIS ───
  args.jobLog('\n--- Audio Analysis ---');

  const audioCategories = {
    english: [], japanese: [], korean: [], french: [],
    unknown: [], commentary: [], other: []
  };

  audioStreams.forEach((stream, arrayIndex) => {
    const lang = detectLanguage(stream);
    const title = stream.tags?.title || '';
    const language = stream.tags?.language || 'und';
    const idx = stream.index;

    args.jobLog(`  Stream ${idx}: "${title}" (${language}) -> ${lang}`);

    if (!validateAudioStream(stream, arrayIndex, args, sourceFile, ffprobePath, ffmpegPath)) {
      args.jobLog(`    -> Skipping (failed validation)`);
      return;
    }

    const cat = lang === 'commentary' ? 'commentary'
      : lang === 'eng' ? 'english'
      : lang === 'jpn' ? 'japanese'
      : lang === 'kor' ? 'korean'
      : lang === 'fre' ? 'french'
      : lang === 'unknown' ? 'unknown'
      : 'other';
    audioCategories[cat].push({ stream, index: idx });
  });

  // Select audio streams to keep
  const keptAudioStreams = [];

  if (audioCategories.english.length > 0) {
    keptAudioStreams.push(audioCategories.english[0]);
    if (audioCategories.english.length > 1) {
      args.jobLog(`Skipping ${audioCategories.english.length - 1} extra English track(s)`);
    }
  }
  keptAudioStreams.push(
    ...audioCategories.japanese,
    ...audioCategories.korean,
    ...audioCategories.french
  );

  if (audioCategories.unknown.length > 0) {
    keptAudioStreams.push(audioCategories.unknown[0]);
    if (audioCategories.unknown.length > 1) {
      args.jobLog(`Keeping only first of ${audioCategories.unknown.length} unknown audio streams`);
    }
  }

  if (keptAudioStreams.length === 0) {
    if (audioCategories.other.length > 0) {
      keptAudioStreams.push(...audioCategories.other);
      args.jobLog('No supported language detected, keeping all non-commentary streams');
    } else if (audioStreams.length > 0) {
      keptAudioStreams.push({ stream: audioStreams[0], index: audioStreams[0].index });
      args.jobLog('FALLBACK: keeping first original audio stream');
    } else {
      args.jobLog('ERROR: No audio streams available');
      return { outputFileObj: args.inputFileObj, outputNumber: 4, variables: args.variables };
    }
  }

  args.jobLog(`Keeping ${keptAudioStreams.length} audio stream(s)`);

  // Check if primary audio is multichannel
  const primaryAudioChannels = parseInt(keptAudioStreams[0].stream.channels || '0', 10);
  const isMultichannel = primaryAudioChannels > 2;
  args.jobLog(`Primary audio: ${primaryAudioChannels} channels (${isMultichannel ? 'multichannel' : 'stereo/mono'})`);

  // ─── STEP 5: SUBTITLE ANALYSIS ───
  args.jobLog('\n--- Subtitle Analysis ---');

  const keptSubtitleStreams = [];

  const subCategories = { english: [], unknown: [] };

  subtitleStreams.forEach((stream) => {
    const title = (stream.tags?.title || '').toLowerCase();
    const language = (stream.tags?.language || '').toLowerCase();
    const codec = stream.codec_name || '';
    const idx = stream.index;
    const arrayIndex = subtitleStreams.indexOf(stream);

    args.jobLog(`  Stream ${idx}: "${stream.tags?.title || ''}" (${language}, ${codec})`);

    if (!validateSubtitleStream(stream, arrayIndex, args, sourceFile, ffprobePath)) {
      args.jobLog(`    -> Skipping (failed validation)`);
      return;
    }

    if (BITMAP_SUBTITLE_CODECS.includes(codec)) {
      args.jobLog(`    -> Skipping (bitmap: ${codec})`);
      return;
    }

    const isEnglish = language === 'eng' || language === 'en' ||
      languagePatterns.eng.some(p => p.test(`${title} ${language}`));

    if (isEnglish) {
      subCategories.english.push({ stream, index: idx, codec });
    } else if (!language || language === 'und' || language === '') {
      subCategories.unknown.push({ stream, index: idx, codec });
    } else {
      args.jobLog(`    -> Skipping (not English: ${language})`);
    }
  });

  // Process English subs
  subCategories.english.forEach(({ stream, index, codec }) => {
    const needsConversion = CONVERTIBLE_SUBTITLE_CODECS.includes(codec);
    keptSubtitleStreams.push({ stream, index, needsConversion, codec });
    args.jobLog(`    -> Keeping${needsConversion ? ` (convert ${codec} to SRT)` : ''}`);
  });

  // Process unknown subs (keep only first)
  if (subCategories.unknown.length > 0) {
    const { stream, index, codec } = subCategories.unknown[0];
    const needsConversion = CONVERTIBLE_SUBTITLE_CODECS.includes(codec);
    keptSubtitleStreams.push({ stream, index, needsConversion, codec });
    if (subCategories.unknown.length > 1) {
      args.jobLog(`Keeping only first of ${subCategories.unknown.length} unknown subtitle streams`);
    }
  }

  args.jobLog(`Keeping ${keptSubtitleStreams.length} subtitle stream(s)`);

  // ─── STEP 6: DESYNC ANALYSIS ───
  args.jobLog('\n--- Desync Analysis ---');

  const keptAudioWithLang = keptAudioStreams.map(({ stream, index }) => ({
    stream, index, lang: detectLanguage(stream)
  }));

  const desyncAnalysis = analyzeAVDesync(videoStreams, keptAudioWithLang, args);
  args.jobLog(`Desync: ${desyncAnalysis.reason}`);

  // ─── STEP 7: ROUTING DECISION ───
  args.jobLog('\n--- Routing Decision ---');

  // Determine if audio processing is needed
  const primaryAudioCodec = (keptAudioStreams[0].stream.codec_name || '').toLowerCase();
  const primaryAudioBitrate = parseInt(keptAudioStreams[0].stream.bit_rate || '0', 10);
  const primaryAudioBitrateKbps = Math.round(primaryAudioBitrate / 1000);

  // Audio is "perfect" if: AAC, stereo, <=128kbps, and we're not dropping streams or fixing desync
  const audioIsAAC = primaryAudioCodec === 'aac';
  const audioIsStereo = primaryAudioChannels <= 2;
  // Check if bitrate is close to our target (128k) -- allow up to 129k for rounding
  const audioBitrateOk = primaryAudioBitrateKbps > 0 && primaryAudioBitrateKbps <= 129;

  const streamsBeingDropped = streams.length > (videoStreams.length + keptAudioStreams.length + keptSubtitleStreams.length);
  const hasSubConversions = keptSubtitleStreams.some(s => s.needsConversion);
  const hasDesync = desyncAnalysis.needsOffset;

  // Check if ALL kept audio streams are already perfect
  let allAudioPerfect = true;
  for (const { stream } of keptAudioStreams) {
    const c = (stream.codec_name || '').toLowerCase();
    const ch = parseInt(stream.channels || '0', 10);
    const br = Math.round(parseInt(stream.bit_rate || '0', 10) / 1000);
    // br === 0 means ffprobe couldn't determine bitrate (common in MKV) -- treat as OK for AAC stereo
    if (c !== 'aac' || ch > 2 || (br > 0 && br > 129)) {
      allAudioPerfect = false;
      break;
    }
  }

  const needsAudioWork = !allAudioPerfect || streamsBeingDropped || hasSubConversions || hasDesync;

  args.jobLog(`Video: ${isHEVC ? 'HEVC' : videoCodec}, re-encode: ${needsVideoReencode}`);
  args.jobLog(`Audio: ${primaryAudioCodec} ${primaryAudioChannels}ch ${primaryAudioBitrateKbps}kbps, all perfect: ${allAudioPerfect}`);
  args.jobLog(`Streams dropped: ${streamsBeingDropped}, sub conversions: ${hasSubConversions}, desync: ${hasDesync}`);
  args.jobLog(`Needs audio work: ${needsAudioWork}, needs video re-encode: ${needsVideoReencode}`);

  // Build the serializable analyzer variables
  const analyzerAudioStreams = keptAudioStreams.map(({ stream, index }) => ({
    index,
    language: detectLanguage(stream),
    channels: parseInt(stream.channels || '0', 10),
    codec: (stream.codec_name || '').toLowerCase(),
    isDefault: index === keptAudioStreams[0].index,
    // Store the audio-relative index for -map commands
    audioRelativeIndex: audioStreams.findIndex(s => s.index === index)
  }));

  const analyzerSubtitleStreams = keptSubtitleStreams.map(({ stream, index, needsConversion, codec }) => ({
    index,
    needsConversion,
    codec,
    // Store the subtitle-relative index for -map commands
    subtitleRelativeIndex: subtitleStreams.findIndex(s => s.index === index)
  }));

  const vars = {
    ...args.variables,
    analyzer_audioStreams: JSON.stringify(analyzerAudioStreams),
    analyzer_subtitleStreams: JSON.stringify(analyzerSubtitleStreams),
    analyzer_videoStreamIndex: primaryVideo.index,
    analyzer_desync: JSON.stringify({
      needsOffset: desyncAnalysis.needsOffset,
      videoStartTime: desyncAnalysis.videoStartTime,
      results: desyncAnalysis.desyncResults
    }),
    analyzer_isMultichannel: isMultichannel,
    analyzer_needsVideoReencode: needsVideoReencode,
    analyzer_videoQualityTier: videoQualityTier,
    analyzer_targetResolution: targetResolution || '',
    analyzer_duration: duration,
    analyzer_videoCodec: videoCodec,
    analyzer_sourceFile: sourceFile
  };

  let outputNumber;
  if (!needsAudioWork && !needsVideoReencode) {
    outputNumber = 1;
    args.jobLog('ROUTE: 1 (skip -- file is perfect)');
  } else if (needsAudioWork && !needsVideoReencode) {
    outputNumber = 2;
    args.jobLog('ROUTE: 2 (audio-only executor)');
  } else {
    outputNumber = 3;
    args.jobLog('ROUTE: 3 (AV executor)');
  }

  args.jobLog('='.repeat(50));
  args.jobLog('   ANALYSIS COMPLETE');
  args.jobLog('='.repeat(50));

  return {
    outputFileObj: args.inputFileObj,
    outputNumber,
    variables: vars
  };
};

// Single-Pass Executor v3
// Reads analyzer variables and builds ONE ffmpeg command for A/V, then uses
// mkvmerge to add subtitles (avoids VLC 3.0 "Unidentified codec" bug).
// - Stream filtering (via -map)
// - A/V desync correction (via -itsoffset)
// - Audio: center-channel boost (pan) + loudnorm + AAC encode (single transcode)
// - Video: copy or HEVC NVENC re-encode
// - Subtitles: mkvmerge adds from source (or converts ASS/SSA/WebVTT -> SRT first)
//
// Used by both audio-only and AV flow paths. Reads analyzer_needsVideoReencode
// from variables to determine behavior.

const VIDEO_QUALITY = {
  '720p_and_below': '-preset p4 -tune hq -rc vbr -b:v 0 -cq 25 -maxrate 2M -bufsize 4M -spatial_aq 1 -temporal_aq 1 -aq-strength 7 -rc-lookahead 16 -g 240 -pix_fmt yuv420p -profile:v main',
  '1080p': '-preset p4 -tune hq -rc vbr -b:v 0 -cq 25 -maxrate 5M -bufsize 10M -spatial_aq 1 -temporal_aq 1 -aq-strength 7 -rc-lookahead 16 -g 240 -pix_fmt yuv420p -profile:v main'
};

const RESOLUTION_SCALE = {
  '480p': '-2:480',
  '720p': '-2:720'
};

function timeToSeconds(timeString) {
  const parts = timeString.split(':');
  return parseInt(parts[0], 10) * 3600 + parseInt(parts[1], 10) * 60 + parseFloat(parts[2]);
}

module.exports = async (args) => {
  const fs = require('fs');
  const path = require('path');
  const { spawn } = require('child_process');

  args.jobLog('='.repeat(50));
  args.jobLog('   SINGLE-PASS EXECUTOR v3');
  args.jobLog('='.repeat(50));

  const v = args.variables || {};

  // Parse analyzer variables
  let analyzerAudio, analyzerSubs, desync;
  try {
    analyzerAudio = JSON.parse(v.analyzer_audioStreams || '[]');
    analyzerSubs = JSON.parse(v.analyzer_subtitleStreams || '[]');
    desync = JSON.parse(v.analyzer_desync || '{"needsOffset":false,"results":[]}');
  } catch (e) {
    args.jobLog(`ERROR: Failed to parse analyzer variables: ${e.message}`);
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  const needsVideoReencode = v.analyzer_needsVideoReencode === true || v.analyzer_needsVideoReencode === 'true';
  const videoQualityTier = v.analyzer_videoQualityTier || '1080p';
  const targetResolution = v.analyzer_targetResolution || '';
  const totalDuration = parseFloat(v.analyzer_duration) || 0;
  const sourceFile = v.analyzer_sourceFile || args.inputFileObj._id || args.inputFileObj.file;

  const ffmpegPath = args.deps.ffmpegPath || 'ffmpeg';
  const ffprobePath = args.deps.ffprobePath || 'ffprobe';

  args.jobLog(`Source: ${sourceFile}`);
  args.jobLog(`Video re-encode: ${needsVideoReencode}`);
  args.jobLog(`Audio streams: ${analyzerAudio.length}`);
  args.jobLog(`Subtitle streams: ${analyzerSubs.length}`);
  args.jobLog(`Desync correction: ${desync.needsOffset}`);

  if (!fs.existsSync(sourceFile)) {
    args.jobLog(`ERROR: Source file does not exist: ${sourceFile}`);
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  // Determine output file path
  let workingDir;
  if (args.workDir && args.workDir.trim() !== '') {
    workingDir = path.normalize(args.workDir);
  } else {
    workingDir = path.dirname(sourceFile);
  }

  if (!fs.existsSync(workingDir)) {
    fs.mkdirSync(workingDir, { recursive: true });
  }

  const baseName = path.basename(sourceFile).replace(/\.[^.]+$/, '');
  const outputFile = path.join(workingDir, `${baseName}.mkv`);
  args.jobLog(`Output: ${outputFile}`);

  // ─── BUILD FFMPEG COMMAND ───
  const ffmpegArgs = [
    '-fflags', '+discardcorrupt+genpts+igndts+flush_packets',
    '-err_detect', 'ignore_err',
    '-analyzeduration', '10000000',
    '-probesize', '10000000',
    '-max_error_rate', '1.0',
    '-ignore_unknown',
    '-progress', 'pipe:2',
    '-stats_period', '1',
    '-v', 'info'
  ];

  // ── Input(s) ──
  // Build a map of audio stream offsets for desync correction
  const audioOffsetMap = new Map();
  if (desync.needsOffset && desync.results) {
    desync.results.forEach(r => audioOffsetMap.set(r.streamIndex, r.desyncOffset));
  }

  // Determine if we need multiple inputs for desync correction
  const needsSplitInputs = desync.needsOffset &&
    analyzerAudio.some(a => Math.abs(audioOffsetMap.get(a.index) || 0) >= 0.001);

  if (needsSplitInputs) {
    // Input 0: video + subtitles (no offset)
    ffmpegArgs.push('-i', sourceFile);
    args.jobLog(`Input 0: ${path.basename(sourceFile)} (video + subs, no offset)`);

    // One additional input per audio stream that needs offset
    let inputIdx = 1;
    const audioInputMap = new Map();

    for (const audio of analyzerAudio) {
      const offset = audioOffsetMap.get(audio.index) || 0;
      if (Math.abs(offset) >= 0.001) {
        ffmpegArgs.push('-itsoffset', offset.toFixed(3));
        args.jobLog(`Input ${inputIdx}: audio stream ${audio.index}, offset ${offset.toFixed(3)}s`);
      } else {
        args.jobLog(`Input ${inputIdx}: audio stream ${audio.index}, no offset`);
      }
      ffmpegArgs.push('-i', sourceFile);
      audioInputMap.set(audio.index, inputIdx);
      inputIdx++;
    }

    // Store for mapping phase
    args._audioInputMap = audioInputMap;
  } else {
    // Single input
    ffmpegArgs.push('-i', sourceFile);
    args.jobLog(`Input 0: ${path.basename(sourceFile)} (all streams)`);
  }

  // Don't copy source metadata — stale BPS/codec stats from the original file
  // confuse some players (VLC "unidentified codec" warning). Only write explicit tags.
  ffmpegArgs.push('-map_metadata', '-1');
  // Preserve chapters from input
  ffmpegArgs.push('-map_chapters', '0');
  ffmpegArgs.push('-max_muxing_queue_size', '1024');

  // ── Video mapping ──
  ffmpegArgs.push('-map', '0:v:0');

  if (needsVideoReencode) {
    ffmpegArgs.push('-c:v', 'hevc_nvenc');

    // Add resolution scaling if specified
    if (targetResolution && RESOLUTION_SCALE[targetResolution]) {
      ffmpegArgs.push('-vf', `scale=${RESOLUTION_SCALE[targetResolution]}`);
      args.jobLog(`Video: HEVC NVENC, scale to ${targetResolution}`);
    } else {
      args.jobLog(`Video: HEVC NVENC, keep resolution`);
    }

    // Quality preset
    const qualityArgs = VIDEO_QUALITY[videoQualityTier] || VIDEO_QUALITY['1080p'];
    ffmpegArgs.push(...qualityArgs.split(' '));
    args.jobLog(`Quality tier: ${videoQualityTier}`);
  } else {
    ffmpegArgs.push('-c:v', 'copy');
    args.jobLog('Video: copy');
  }

  // ── Audio mapping ──
  if (analyzerAudio.length === 0) {
    ffmpegArgs.push('-an');
    args.jobLog('Audio: none');
  } else {
    for (let i = 0; i < analyzerAudio.length; i++) {
      const audio = analyzerAudio[i];

      if (needsSplitInputs) {
        // Map from the corresponding input
        const inputIdx = args._audioInputMap.get(audio.index);
        ffmpegArgs.push('-map', `${inputIdx}:a:${audio.audioRelativeIndex}`);
      } else {
        // Map from single input
        ffmpegArgs.push('-map', `0:a:${audio.audioRelativeIndex}`);
      }

      // Audio filter: center-channel boost for multichannel, loudnorm for all
      if (audio.channels > 2) {
        // Multichannel -> stereo downmix with center boost + loudnorm
        ffmpegArgs.push(
          `-filter:a:${i}`,
          'pan=stereo|FL<1.0*FL+1.2*FC+0.6*BL+0.6*SL|FR<1.0*FR+1.2*FC+0.6*BR+0.6*SR,loudnorm=I=-16:LRA=11:TP=-1.5'
        );
        args.jobLog(`Audio ${i}: stream ${audio.index} (${audio.language}, ${audio.channels}ch -> stereo, center boost + loudnorm)`);
      } else {
        // Stereo/mono -> loudnorm only
        ffmpegArgs.push(`-filter:a:${i}`, 'loudnorm=I=-16:LRA=11:TP=-1.5');
        args.jobLog(`Audio ${i}: stream ${audio.index} (${audio.language}, ${audio.channels}ch, loudnorm)`);
      }

      // AAC encoding
      ffmpegArgs.push(`-c:a:${i}`, 'aac');
      ffmpegArgs.push(`-b:a:${i}`, '128k');
      ffmpegArgs.push(`-ar:a:${i}`, '48000');

      // Language metadata
      const langCode = ['eng', 'jpn', 'kor', 'fre'].includes(audio.language) ? audio.language : 'und';
      ffmpegArgs.push(`-metadata:s:a:${i}`, `language=${langCode}`);

      // Default disposition
      if (audio.isDefault) {
        ffmpegArgs.push(`-disposition:a:${i}`, 'default');
      } else {
        ffmpegArgs.push(`-disposition:a:${i}`, '0');
      }
    }
  }

  // ── Subtitles: always exclude from ffmpeg (added via mkvmerge later) ──
  // ffmpeg's matroska muxer writes subtitle CodecID entries that VLC 3.0's
  // avformat demuxer can't map to a valid fourcc, causing "Unidentified codec".
  // mkvmerge writes proper S_TEXT/UTF8 entries that work everywhere.
  ffmpegArgs.push('-sn');
  if (analyzerSubs.length > 0) {
    args.jobLog(`Subtitles: ${analyzerSubs.length} track(s) deferred to mkvmerge step`);
  } else {
    args.jobLog('Subtitles: none');
  }

  // ── Output flags ──
  ffmpegArgs.push('-avoid_negative_ts', 'make_zero');
  ffmpegArgs.push('-y', outputFile);

  // Log the full command
  args.jobLog(`\nFFmpeg command:\n${ffmpegPath} ${ffmpegArgs.join(' ')}`);

  // Clean up temp property
  delete args._audioInputMap;

  // ─── EXECUTE FFMPEG ───
  args.jobLog('\n--- Executing FFmpeg ---');

  if (args.updateWorker) {
    args.updateWorker({
      CLIType: ffmpegPath,
      preset: ffmpegArgs.join(' ')
    });
  }

  await new Promise((resolve, reject) => {
    const proc = spawn(ffmpegPath, ffmpegArgs);

    let stderrData = '';
    let lastPercentage = 0;

    proc.stderr.on('data', (data) => {
      const text = data.toString();
      stderrData += text;

      // Parse full progress line
      const match = text.match(
        /frame=\s*(\d+)\s+fps=\s*([\d.]+)\s+q=\s*([\d.-]+)\s+size=\s*(\d+)(\w+)\s+time=(\d{2}:\d{2}:\d{2}\.\d{2})\s+bitrate=\s*([\d.]+)(\w+\/s)\s+speed=\s*([\d.]+)x/
      );

      if (match) {
        const [, frame, fps, quality, sizeVal, sizeUnit, timeStr, brVal, brUnit, speed] = match;

        let sizeKiB = parseInt(sizeVal, 10);
        if (sizeUnit.toLowerCase() === 'mib') sizeKiB = Math.round(sizeKiB * 1024);
        else if (sizeUnit.toLowerCase() === 'gib') sizeKiB = Math.round(sizeKiB * 1024 * 1024);

        args.jobLog(`frame=${frame} fps=${fps} q=${quality} size=${sizeKiB}KiB time=${timeStr} bitrate=${brVal}${brUnit} speed=${speed}x`);

        if (totalDuration > 0) {
          try {
            const currentSec = timeToSeconds(timeStr);
            const pct = Math.min(Math.round((currentSec / totalDuration) * 100), 100);

            if (args.updateWorker && (pct !== lastPercentage || pct % 5 === 0)) {
              lastPercentage = pct;
              args.updateWorker({
                CLIType: ffmpegPath,
                preset: ffmpegArgs.join(' '),
                percentage: pct,
                frame: parseInt(frame, 10),
                fps: parseFloat(fps),
                speed: parseFloat(speed),
                bitrate: `${brVal}${brUnit}`,
                time: timeStr,
                size: `${sizeKiB}KiB`
              });
              args.jobLog(`Progress: ${pct}%`);
            }
          } catch (_) {
            // ignore parse errors in progress
          }
        }
      } else {
        // Fallback: basic time parsing
        const timeMatch = text.match(/time=(\d{2}:\d{2}:\d{2}\.\d{2})/);
        if (timeMatch && totalDuration > 0) {
          try {
            const currentSec = timeToSeconds(timeMatch[1]);
            const pct = Math.min(Math.round((currentSec / totalDuration) * 100), 100);
            if (args.updateWorker && pct !== lastPercentage && pct % 5 === 0) {
              lastPercentage = pct;
              args.updateWorker({
                CLIType: ffmpegPath,
                preset: ffmpegArgs.join(' '),
                percentage: pct,
                time: timeMatch[1]
              });
              args.jobLog(`Progress: ${pct}%`);
            }
          } catch (_) {}
        }
      }

      // Log errors/warnings
      if (text.includes('Error') || text.includes('Warning')) {
        args.jobLog(`FFmpeg: ${text.trim()}`);
      }
    });

    proc.on('close', (code) => {
      if (code !== 0) {
        args.jobLog(`ERROR: FFmpeg exit code ${code}`);
        args.jobLog(`Stderr (last 2000 chars): ${stderrData.slice(-2000)}`);
        if (args.updateWorker) {
          args.updateWorker({ CLIType: ffmpegPath, percentage: 0, error: `FFmpeg exit ${code}` });
        }
        reject(new Error(`FFmpeg failed with exit code ${code}`));
      } else {
        args.jobLog('FFmpeg completed successfully');
        if (args.updateWorker) {
          args.updateWorker({ CLIType: ffmpegPath, percentage: 100 });
        }
        resolve();
      }
    });

    proc.on('error', (err) => {
      args.jobLog(`ERROR: Failed to start FFmpeg: ${err.message}`);
      reject(err);
    });
  });

  // ─── MKVMERGE: ADD SUBTITLES ───
  // mkvmerge produces proper S_TEXT/UTF8 codec entries that VLC 3.0 recognises,
  // unlike ffmpeg's matroska muxer which writes entries that trigger
  // "Unidentified codec" in VLC's avformat demuxer.
  if (analyzerSubs.length > 0) {
    args.jobLog('\n--- Adding subtitles via mkvmerge ---');

    const { execFileSync } = require('child_process');

    // Locate mkvmerge — same dir as mkvpropedit if available
    let mkvmergePath = 'mkvmerge';
    if (args.deps.mkvpropeditPath) {
      const mkvDir = path.dirname(args.deps.mkvpropeditPath);
      const candidate = path.join(mkvDir, 'mkvmerge');
      if (fs.existsSync(candidate)) {
        mkvmergePath = candidate;
      }
    }
    args.jobLog(`mkvmerge path: ${mkvmergePath}`);

    const tempSubFiles = [];
    const mkvmergeArgs = ['-o', `${outputFile}.mux.mkv`, outputFile];

    // Extract each subtitle via ffmpeg to a temp SRT file, then add via mkvmerge.
    // This avoids ffprobe-index vs mkvmerge-TID mapping issues and ensures all
    // subs end up as proper S_TEXT/UTF8 regardless of source format.
    for (let i = 0; i < analyzerSubs.length; i++) {
      const sub = analyzerSubs[i];
      const langCode = sub.language || 'eng';
      // Always set default_track to 'no' — VLC 3.0's avformat demuxer auto-selects
      // default subtitle tracks and fails with "Unidentified codec" (undf fourcc).
      // Setting to 'no' prevents auto-selection while keeping subs available.
      const isDefault = 'no';
      const tempSrt = path.join(workingDir, `_temp_sub_${i}.srt`);

      const action = sub.needsConversion
        ? `converting stream ${sub.index} (${sub.codec}) -> SRT`
        : `extracting stream ${sub.index} (${sub.codec}) as SRT`;
      args.jobLog(`Subtitle ${i}: ${action}`);

      try {
        execFileSync(ffmpegPath, [
          '-i', sourceFile,
          '-map', `0:${sub.index}`,
          '-c:s', 'srt',
          '-y', tempSrt
        ], { encoding: 'utf8', maxBuffer: 1024 * 1024 * 10 });
      } catch (e) {
        args.jobLog(`WARNING: Sub extraction failed for stream ${sub.index}: ${e.message}`);
        continue;
      }

      tempSubFiles.push(tempSrt);
      mkvmergeArgs.push(
        '--language', `0:${langCode}`,
        '--default-track-flag', `0:${isDefault}`,
        tempSrt
      );
      args.jobLog(`Subtitle ${i}: queued temp SRT (lang=${langCode}, default=${isDefault})`);
    }

    args.jobLog(`mkvmerge command:\n${mkvmergePath} ${mkvmergeArgs.join(' ')}`);

    try {
      const mkvResult = execFileSync(mkvmergePath, mkvmergeArgs, {
        encoding: 'utf8',
        maxBuffer: 1024 * 1024 * 10
      });
      args.jobLog(`mkvmerge output: ${mkvResult.trim()}`);

      // Replace ffmpeg output with mkvmerge output
      fs.unlinkSync(outputFile);
      fs.renameSync(`${outputFile}.mux.mkv`, outputFile);
      args.jobLog('mkvmerge: replaced ffmpeg output with muxed file');
    } catch (e) {
      args.jobLog(`ERROR: mkvmerge failed: ${e.message}`);
      // Clean up temp mux file if it exists
      try { fs.unlinkSync(`${outputFile}.mux.mkv`); } catch (_) {}
      // Fall back to ffmpeg-only output (no subs, but at least A/V work)
      args.jobLog('WARNING: Falling back to ffmpeg output without subtitles');
    }

    // Clean up temp subtitle files
    for (const tmp of tempSubFiles) {
      try { fs.unlinkSync(tmp); } catch (_) {}
    }
  }

  // ─── VERIFY OUTPUT ───
  args.jobLog('\n--- Verifying Output ---');

  if (!fs.existsSync(outputFile)) {
    args.jobLog('ERROR: Output file not created');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  // Probe output
  let outputProbe;
  try {
    const { execFileSync } = require('child_process');
    const probeResult = execFileSync(ffprobePath, [
      '-v', 'quiet', '-print_format', 'json',
      '-show_streams', '-show_format', outputFile
    ], { encoding: 'utf8', maxBuffer: 1024 * 1024 * 10 });
    outputProbe = JSON.parse(probeResult);
  } catch (e) {
    args.jobLog(`ERROR: Cannot probe output: ${e.message}`);
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  const outStreams = outputProbe.streams || [];
  const outVideo = outStreams.filter(s => s.codec_type === 'video');
  const outAudio = outStreams.filter(s => s.codec_type === 'audio');
  const outSubs = outStreams.filter(s => s.codec_type === 'subtitle');

  args.jobLog(`Output streams: ${outVideo.length} video, ${outAudio.length} audio, ${outSubs.length} subtitle`);

  // Validate streams
  if (outVideo.length === 0) {
    args.jobLog('ERROR: No video in output');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }
  if (analyzerAudio.length > 0 && outAudio.length === 0) {
    args.jobLog('ERROR: No audio in output');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  // Log output details
  outAudio.forEach((s, i) => {
    args.jobLog(`  Audio ${i}: ${s.codec_name} ${s.channels}ch ${Math.round((parseInt(s.bit_rate || '0', 10)) / 1000)}kbps ${s.tags?.language || 'und'}`);
  });
  if (needsVideoReencode) {
    args.jobLog(`  Video: ${outVideo[0].codec_name} ${outVideo[0].width}x${outVideo[0].height}`);
  }

  const sourceStats = fs.statSync(sourceFile);
  const outputStats = fs.statSync(outputFile);
  args.jobLog(`Size: ${(sourceStats.size / 1024 / 1024).toFixed(1)}MB -> ${(outputStats.size / 1024 / 1024).toFixed(1)}MB`);

  args.jobLog('='.repeat(50));
  args.jobLog('   EXECUTION COMPLETE');
  args.jobLog('='.repeat(50));

  // Return processed file
  const normalizedOutput = outputFile.replace(/\\/g, '/');

  return {
    outputFileObj: {
      ...args.inputFileObj,
      _id: normalizedOutput
    },
    outputNumber: 1,
    variables: {
      ...v,
      requiresReplacement: true,
      preprocessed: true
    }
  };
};

// Single-Pass Executor v3
// Reads analyzer variables and builds ONE ffmpeg command for A/V, then uses
// mkvmerge to add subtitles (avoids VLC 3.0 "Unidentified codec" bug).
// - Stream filtering (via -map)
// - A/V desync correction (via -itsoffset)
// - Audio: center-channel boost (pan) + loudnorm + AAC encode (single transcode)
// - Video: copy or HEVC NVENC re-encode
// - Subtitles: mkvmerge adds from source (or converts ASS/SSA/WebVTT -> SRT first)
//
// Used by both audio-only and AV flow paths. Reads analyzer_needsVideoReencode
// from variables to determine behavior.

const VIDEO_QUALITY = {
  '720p_and_below': '-preset p4 -tune hq -rc vbr -b:v 0 -cq 25 -maxrate 2M -bufsize 4M -spatial_aq 1 -temporal_aq 1 -aq-strength 7 -rc-lookahead 16 -g 240 -pix_fmt yuv420p -profile:v main',
  '1080p': '-preset p4 -tune hq -rc vbr -b:v 0 -cq 25 -maxrate 5M -bufsize 10M -spatial_aq 1 -temporal_aq 1 -aq-strength 7 -rc-lookahead 16 -g 240 -pix_fmt yuv420p -profile:v main'
};

const RESOLUTION_SCALE = {
  '480p': '-2:480',
  '720p': '-2:720'
};

function timeToSeconds(timeString) {
  const parts = timeString.split(':');
  return parseInt(parts[0], 10) * 3600 + parseInt(parts[1], 10) * 60 + parseFloat(parts[2]);
}

module.exports = async (args) => {
  const fs = require('fs');
  const path = require('path');
  const { spawn } = require('child_process');

  args.jobLog('='.repeat(50));
  args.jobLog('   SINGLE-PASS EXECUTOR v3');
  args.jobLog('='.repeat(50));

  const v = args.variables || {};

  // Parse analyzer variables
  let analyzerAudio, analyzerSubs, desync;
  try {
    analyzerAudio = JSON.parse(v.analyzer_audioStreams || '[]');
    analyzerSubs = JSON.parse(v.analyzer_subtitleStreams || '[]');
    desync = JSON.parse(v.analyzer_desync || '{"needsOffset":false,"results":[]}');
  } catch (e) {
    args.jobLog(`ERROR: Failed to parse analyzer variables: ${e.message}`);
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  const needsVideoReencode = v.analyzer_needsVideoReencode === true || v.analyzer_needsVideoReencode === 'true';
  const videoQualityTier = v.analyzer_videoQualityTier || '1080p';
  const targetResolution = v.analyzer_targetResolution || '';
  const totalDuration = parseFloat(v.analyzer_duration) || 0;
  const sourceFile = v.analyzer_sourceFile || args.inputFileObj._id || args.inputFileObj.file;

  const ffmpegPath = args.deps.ffmpegPath || 'ffmpeg';
  const ffprobePath = args.deps.ffprobePath || 'ffprobe';

  args.jobLog(`Source: ${sourceFile}`);
  args.jobLog(`Video re-encode: ${needsVideoReencode}`);
  args.jobLog(`Audio streams: ${analyzerAudio.length}`);
  args.jobLog(`Subtitle streams: ${analyzerSubs.length}`);
  args.jobLog(`Desync correction: ${desync.needsOffset}`);

  if (!fs.existsSync(sourceFile)) {
    args.jobLog(`ERROR: Source file does not exist: ${sourceFile}`);
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  // Determine output file path
  let workingDir;
  if (args.workDir && args.workDir.trim() !== '') {
    workingDir = path.normalize(args.workDir);
  } else {
    workingDir = path.dirname(sourceFile);
  }

  if (!fs.existsSync(workingDir)) {
    fs.mkdirSync(workingDir, { recursive: true });
  }

  const baseName = path.basename(sourceFile).replace(/\.[^.]+$/, '');
  const outputFile = path.join(workingDir, `${baseName}.mkv`);
  args.jobLog(`Output: ${outputFile}`);

  // ─── BUILD FFMPEG COMMAND ───
  const ffmpegArgs = [
    '-fflags', '+discardcorrupt+genpts+igndts+flush_packets',
    '-err_detect', 'ignore_err',
    '-analyzeduration', '10000000',
    '-probesize', '10000000',
    '-max_error_rate', '1.0',
    '-ignore_unknown',
    '-progress', 'pipe:2',
    '-stats_period', '1',
    '-v', 'info'
  ];

  // ── Input(s) ──
  // Build a map of audio stream offsets for desync correction
  const audioOffsetMap = new Map();
  if (desync.needsOffset && desync.results) {
    desync.results.forEach(r => audioOffsetMap.set(r.streamIndex, r.desyncOffset));
  }

  // Determine if we need multiple inputs for desync correction
  const needsSplitInputs = desync.needsOffset &&
    analyzerAudio.some(a => Math.abs(audioOffsetMap.get(a.index) || 0) >= 0.001);

  if (needsSplitInputs) {
    // Input 0: video + subtitles (no offset)
    ffmpegArgs.push('-i', sourceFile);
    args.jobLog(`Input 0: ${path.basename(sourceFile)} (video + subs, no offset)`);

    // One additional input per audio stream that needs offset
    let inputIdx = 1;
    const audioInputMap = new Map();

    for (const audio of analyzerAudio) {
      const offset = audioOffsetMap.get(audio.index) || 0;
      if (Math.abs(offset) >= 0.001) {
        ffmpegArgs.push('-itsoffset', offset.toFixed(3));
        args.jobLog(`Input ${inputIdx}: audio stream ${audio.index}, offset ${offset.toFixed(3)}s`);
      } else {
        args.jobLog(`Input ${inputIdx}: audio stream ${audio.index}, no offset`);
      }
      ffmpegArgs.push('-i', sourceFile);
      audioInputMap.set(audio.index, inputIdx);
      inputIdx++;
    }

    // Store for mapping phase
    args._audioInputMap = audioInputMap;
  } else {
    // Single input
    ffmpegArgs.push('-i', sourceFile);
    args.jobLog(`Input 0: ${path.basename(sourceFile)} (all streams)`);
  }

  // Don't copy source metadata — stale BPS/codec stats from the original file
  // confuse some players (VLC "unidentified codec" warning). Only write explicit tags.
  ffmpegArgs.push('-map_metadata', '-1');
  // Preserve chapters from input
  ffmpegArgs.push('-map_chapters', '0');
  ffmpegArgs.push('-max_muxing_queue_size', '1024');

  // ── Video mapping ──
  ffmpegArgs.push('-map', '0:v:0');

  if (needsVideoReencode) {
    ffmpegArgs.push('-c:v', 'hevc_nvenc');

    // Add resolution scaling if specified
    if (targetResolution && RESOLUTION_SCALE[targetResolution]) {
      ffmpegArgs.push('-vf', `scale=${RESOLUTION_SCALE[targetResolution]}`);
      args.jobLog(`Video: HEVC NVENC, scale to ${targetResolution}`);
    } else {
      args.jobLog(`Video: HEVC NVENC, keep resolution`);
    }

    // Quality preset
    const qualityArgs = VIDEO_QUALITY[videoQualityTier] || VIDEO_QUALITY['1080p'];
    ffmpegArgs.push(...qualityArgs.split(' '));
    args.jobLog(`Quality tier: ${videoQualityTier}`);
  } else {
    ffmpegArgs.push('-c:v', 'copy');
    args.jobLog('Video: copy');
  }

  // ── Audio mapping ──
  if (analyzerAudio.length === 0) {
    ffmpegArgs.push('-an');
    args.jobLog('Audio: none');
  } else {
    for (let i = 0; i < analyzerAudio.length; i++) {
      const audio = analyzerAudio[i];

      if (needsSplitInputs) {
        // Map from the corresponding input
        const inputIdx = args._audioInputMap.get(audio.index);
        ffmpegArgs.push('-map', `${inputIdx}:a:${audio.audioRelativeIndex}`);
      } else {
        // Map from single input
        ffmpegArgs.push('-map', `0:a:${audio.audioRelativeIndex}`);
      }

      // Audio filter: center-channel boost for multichannel, loudnorm for all
      if (audio.channels > 2) {
        // Multichannel -> stereo downmix with center boost + loudnorm
        ffmpegArgs.push(
          `-filter:a:${i}`,
          'pan=stereo|FL<1.0*FL+1.2*FC+0.6*BL+0.6*SL|FR<1.0*FR+1.2*FC+0.6*BR+0.6*SR,loudnorm=I=-16:LRA=11:TP=-1.5'
        );
        args.jobLog(`Audio ${i}: stream ${audio.index} (${audio.language}, ${audio.channels}ch -> stereo, center boost + loudnorm)`);
      } else {
        // Stereo/mono -> loudnorm only
        ffmpegArgs.push(`-filter:a:${i}`, 'loudnorm=I=-16:LRA=11:TP=-1.5');
        args.jobLog(`Audio ${i}: stream ${audio.index} (${audio.language}, ${audio.channels}ch, loudnorm)`);
      }

      // AAC encoding
      ffmpegArgs.push(`-c:a:${i}`, 'aac');
      ffmpegArgs.push(`-b:a:${i}`, '128k');
      ffmpegArgs.push(`-ar:a:${i}`, '48000');

      // Language metadata
      const langCode = ['eng', 'jpn', 'kor', 'fre'].includes(audio.language) ? audio.language : 'und';
      ffmpegArgs.push(`-metadata:s:a:${i}`, `language=${langCode}`);

      // Default disposition
      if (audio.isDefault) {
        ffmpegArgs.push(`-disposition:a:${i}`, 'default');
      } else {
        ffmpegArgs.push(`-disposition:a:${i}`, '0');
      }
    }
  }

  // ── Subtitles: always exclude from ffmpeg (added via mkvmerge later) ──
  // ffmpeg's matroska muxer writes subtitle CodecID entries that VLC 3.0's
  // avformat demuxer can't map to a valid fourcc, causing "Unidentified codec".
  // mkvmerge writes proper S_TEXT/UTF8 entries that work everywhere.
  ffmpegArgs.push('-sn');
  if (analyzerSubs.length > 0) {
    args.jobLog(`Subtitles: ${analyzerSubs.length} track(s) deferred to mkvmerge step`);
  } else {
    args.jobLog('Subtitles: none');
  }

  // ── Output flags ──
  ffmpegArgs.push('-avoid_negative_ts', 'make_zero');
  ffmpegArgs.push('-y', outputFile);

  // Log the full command
  args.jobLog(`\nFFmpeg command:\n${ffmpegPath} ${ffmpegArgs.join(' ')}`);

  // Clean up temp property
  delete args._audioInputMap;

  // ─── EXECUTE FFMPEG ───
  args.jobLog('\n--- Executing FFmpeg ---');

  if (args.updateWorker) {
    args.updateWorker({
      CLIType: ffmpegPath,
      preset: ffmpegArgs.join(' ')
    });
  }

  await new Promise((resolve, reject) => {
    const proc = spawn(ffmpegPath, ffmpegArgs);

    let stderrData = '';
    let lastPercentage = 0;

    proc.stderr.on('data', (data) => {
      const text = data.toString();
      stderrData += text;

      // Parse full progress line
      const match = text.match(
        /frame=\s*(\d+)\s+fps=\s*([\d.]+)\s+q=\s*([\d.-]+)\s+size=\s*(\d+)(\w+)\s+time=(\d{2}:\d{2}:\d{2}\.\d{2})\s+bitrate=\s*([\d.]+)(\w+\/s)\s+speed=\s*([\d.]+)x/
      );

      if (match) {
        const [, frame, fps, quality, sizeVal, sizeUnit, timeStr, brVal, brUnit, speed] = match;

        let sizeKiB = parseInt(sizeVal, 10);
        if (sizeUnit.toLowerCase() === 'mib') sizeKiB = Math.round(sizeKiB * 1024);
        else if (sizeUnit.toLowerCase() === 'gib') sizeKiB = Math.round(sizeKiB * 1024 * 1024);

        args.jobLog(`frame=${frame} fps=${fps} q=${quality} size=${sizeKiB}KiB time=${timeStr} bitrate=${brVal}${brUnit} speed=${speed}x`);

        if (totalDuration > 0) {
          try {
            const currentSec = timeToSeconds(timeStr);
            const pct = Math.min(Math.round((currentSec / totalDuration) * 100), 100);

            if (args.updateWorker && (pct !== lastPercentage || pct % 5 === 0)) {
              lastPercentage = pct;
              args.updateWorker({
                CLIType: ffmpegPath,
                preset: ffmpegArgs.join(' '),
                percentage: pct,
                frame: parseInt(frame, 10),
                fps: parseFloat(fps),
                speed: parseFloat(speed),
                bitrate: `${brVal}${brUnit}`,
                time: timeStr,
                size: `${sizeKiB}KiB`
              });
              args.jobLog(`Progress: ${pct}%`);
            }
          } catch (_) {
            // ignore parse errors in progress
          }
        }
      } else {
        // Fallback: basic time parsing
        const timeMatch = text.match(/time=(\d{2}:\d{2}:\d{2}\.\d{2})/);
        if (timeMatch && totalDuration > 0) {
          try {
            const currentSec = timeToSeconds(timeMatch[1]);
            const pct = Math.min(Math.round((currentSec / totalDuration) * 100), 100);
            if (args.updateWorker && pct !== lastPercentage && pct % 5 === 0) {
              lastPercentage = pct;
              args.updateWorker({
                CLIType: ffmpegPath,
                preset: ffmpegArgs.join(' '),
                percentage: pct,
                time: timeMatch[1]
              });
              args.jobLog(`Progress: ${pct}%`);
            }
          } catch (_) {}
        }
      }

      // Log errors/warnings
      if (text.includes('Error') || text.includes('Warning')) {
        args.jobLog(`FFmpeg: ${text.trim()}`);
      }
    });

    proc.on('close', (code) => {
      if (code !== 0) {
        args.jobLog(`ERROR: FFmpeg exit code ${code}`);
        args.jobLog(`Stderr (last 2000 chars): ${stderrData.slice(-2000)}`);
        if (args.updateWorker) {
          args.updateWorker({ CLIType: ffmpegPath, percentage: 0, error: `FFmpeg exit ${code}` });
        }
        reject(new Error(`FFmpeg failed with exit code ${code}`));
      } else {
        args.jobLog('FFmpeg completed successfully');
        if (args.updateWorker) {
          args.updateWorker({ CLIType: ffmpegPath, percentage: 100 });
        }
        resolve();
      }
    });

    proc.on('error', (err) => {
      args.jobLog(`ERROR: Failed to start FFmpeg: ${err.message}`);
      reject(err);
    });
  });

  // ─── MKVMERGE: ADD SUBTITLES ───
  // mkvmerge produces proper S_TEXT/UTF8 codec entries that VLC 3.0 recognises,
  // unlike ffmpeg's matroska muxer which writes entries that trigger
  // "Unidentified codec" in VLC's avformat demuxer.
  if (analyzerSubs.length > 0) {
    args.jobLog('\n--- Adding subtitles via mkvmerge ---');

    const { execFileSync } = require('child_process');

    // Locate mkvmerge — same dir as mkvpropedit if available
    let mkvmergePath = 'mkvmerge';
    if (args.deps.mkvpropeditPath) {
      const mkvDir = path.dirname(args.deps.mkvpropeditPath);
      const candidate = path.join(mkvDir, 'mkvmerge');
      if (fs.existsSync(candidate)) {
        mkvmergePath = candidate;
      }
    }
    args.jobLog(`mkvmerge path: ${mkvmergePath}`);

    const tempSubFiles = [];
    const mkvmergeArgs = ['-o', `${outputFile}.mux.mkv`, outputFile];

    // Extract each subtitle via ffmpeg to a temp SRT file, then add via mkvmerge.
    // This avoids ffprobe-index vs mkvmerge-TID mapping issues and ensures all
    // subs end up as proper S_TEXT/UTF8 regardless of source format.
    for (let i = 0; i < analyzerSubs.length; i++) {
      const sub = analyzerSubs[i];
      const langCode = sub.language || 'eng';
      // Always set default_track to 'no' — VLC 3.0's avformat demuxer auto-selects
      // default subtitle tracks and fails with "Unidentified codec" (undf fourcc).
      // Setting to 'no' prevents auto-selection while keeping subs available.
      const isDefault = 'no';
      const tempSrt = path.join(workingDir, `_temp_sub_${i}.srt`);

      const action = sub.needsConversion
        ? `converting stream ${sub.index} (${sub.codec}) -> SRT`
        : `extracting stream ${sub.index} (${sub.codec}) as SRT`;
      args.jobLog(`Subtitle ${i}: ${action}`);

      try {
        execFileSync(ffmpegPath, [
          '-i', sourceFile,
          '-map', `0:${sub.index}`,
          '-c:s', 'srt',
          '-y', tempSrt
        ], { encoding: 'utf8', maxBuffer: 1024 * 1024 * 10 });
      } catch (e) {
        args.jobLog(`WARNING: Sub extraction failed for stream ${sub.index}: ${e.message}`);
        continue;
      }

      tempSubFiles.push(tempSrt);
      mkvmergeArgs.push(
        '--language', `0:${langCode}`,
        '--default-track-flag', `0:${isDefault}`,
        tempSrt
      );
      args.jobLog(`Subtitle ${i}: queued temp SRT (lang=${langCode}, default=${isDefault})`);
    }

    args.jobLog(`mkvmerge command:\n${mkvmergePath} ${mkvmergeArgs.join(' ')}`);

    try {
      const mkvResult = execFileSync(mkvmergePath, mkvmergeArgs, {
        encoding: 'utf8',
        maxBuffer: 1024 * 1024 * 10
      });
      args.jobLog(`mkvmerge output: ${mkvResult.trim()}`);

      // Replace ffmpeg output with mkvmerge output
      fs.unlinkSync(outputFile);
      fs.renameSync(`${outputFile}.mux.mkv`, outputFile);
      args.jobLog('mkvmerge: replaced ffmpeg output with muxed file');
    } catch (e) {
      args.jobLog(`ERROR: mkvmerge failed: ${e.message}`);
      // Clean up temp mux file if it exists
      try { fs.unlinkSync(`${outputFile}.mux.mkv`); } catch (_) {}
      // Fall back to ffmpeg-only output (no subs, but at least A/V work)
      args.jobLog('WARNING: Falling back to ffmpeg output without subtitles');
    }

    // Clean up temp subtitle files
    for (const tmp of tempSubFiles) {
      try { fs.unlinkSync(tmp); } catch (_) {}
    }
  }

  // ─── VERIFY OUTPUT ───
  args.jobLog('\n--- Verifying Output ---');

  if (!fs.existsSync(outputFile)) {
    args.jobLog('ERROR: Output file not created');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  // Probe output
  let outputProbe;
  try {
    const { execFileSync } = require('child_process');
    const probeResult = execFileSync(ffprobePath, [
      '-v', 'quiet', '-print_format', 'json',
      '-show_streams', '-show_format', outputFile
    ], { encoding: 'utf8', maxBuffer: 1024 * 1024 * 10 });
    outputProbe = JSON.parse(probeResult);
  } catch (e) {
    args.jobLog(`ERROR: Cannot probe output: ${e.message}`);
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  const outStreams = outputProbe.streams || [];
  const outVideo = outStreams.filter(s => s.codec_type === 'video');
  const outAudio = outStreams.filter(s => s.codec_type === 'audio');
  const outSubs = outStreams.filter(s => s.codec_type === 'subtitle');

  args.jobLog(`Output streams: ${outVideo.length} video, ${outAudio.length} audio, ${outSubs.length} subtitle`);

  // Validate streams
  if (outVideo.length === 0) {
    args.jobLog('ERROR: No video in output');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }
  if (analyzerAudio.length > 0 && outAudio.length === 0) {
    args.jobLog('ERROR: No audio in output');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: v };
  }

  // Log output details
  outAudio.forEach((s, i) => {
    args.jobLog(`  Audio ${i}: ${s.codec_name} ${s.channels}ch ${Math.round((parseInt(s.bit_rate || '0', 10)) / 1000)}kbps ${s.tags?.language || 'und'}`);
  });
  if (needsVideoReencode) {
    args.jobLog(`  Video: ${outVideo[0].codec_name} ${outVideo[0].width}x${outVideo[0].height}`);
  }

  const sourceStats = fs.statSync(sourceFile);
  const outputStats = fs.statSync(outputFile);
  args.jobLog(`Size: ${(sourceStats.size / 1024 / 1024).toFixed(1)}MB -> ${(outputStats.size / 1024 / 1024).toFixed(1)}MB`);

  args.jobLog('='.repeat(50));
  args.jobLog('   EXECUTION COMPLETE');
  args.jobLog('='.repeat(50));

  // Return processed file
  const normalizedOutput = outputFile.replace(/\\/g, '/');

  return {
    outputFileObj: {
      ...args.inputFileObj,
      _id: normalizedOutput
    },
    outputNumber: 1,
    variables: {
      ...v,
      requiresReplacement: true,
      preprocessed: true
    }
  };
};

// Tdarr Flow Custom JS Plugin: Robust A/V Stream Guard (lock-aware)
// - Verifies audio/video streams on the current working file (prefers outputFileObj, else inputFileObj)
// - Retries around transient file locks (EBUSY/EPERM/ENOENT) before probing
// - Uses ffprobe with larger buffer + timeout and path overrides
// - Optional "synthetic streams" fallback via args.variables.avguard_allowSynthetic (default: false)
// - Detects dropped streams by comparing to original input
//
// ---- Runtime knobs (set in Flow variables or previous blocks) ----
// variables.avguard_allowSynthetic: boolean  (default: false)
// variables.avguard_ffprobePath:   string   (default: args.deps.ffprobePath || process.env.FFPROBE_PATH || 'ffprobe')
// variables.avguard_retryTries:    number   (default: 6)            // total attempts for lock/ffprobe
// variables.avguard_retryDelayMs:  number   (default: 300)          // initial backoff (exponential)
// variables.avguard_probeTimeout:  number   (default: 15000)        // ms
// variables.avguard_maxBufferMB:   number   (default: 64)           // ffprobe JSON max buffer
//
// Notes:
// - Place Tdarr work/cache on a local, AV-excluded path to minimize EBUSY.
// - Give each worker a unique workDir to avoid temp-file collisions.

module.exports = async (args) => {
  try {
    const fileObj = args.outputFileObj ?? args.inputFileObj;
    if (!fileObj) {
      args.jobLog('❌ No file object provided to stream-check block.');
      return {
        outputFileObj: args.outputFileObj ?? args.inputFileObj,
        outputNumber: 2,
        error: 'No file to inspect',
      };
    }

    // --- Config from variables with sane defaults ---
    const v = args.variables || {};
    const allowSynthetic = Boolean(v.avguard_allowSynthetic ?? false);
    const ffprobePath =
      v.avguard_ffprobePath ||
      args?.deps?.ffprobePath ||
      process.env.FFPROBE_PATH ||
      'ffprobe';

    const retryTries   = Number.isFinite(v.avguard_retryTries)   ? v.avguard_retryTries   : 6;
    const retryDelayMs = Number.isFinite(v.avguard_retryDelayMs) ? v.avguard_retryDelayMs : 300;
    const probeTimeout = Number.isFinite(v.avguard_probeTimeout) ? v.avguard_probeTimeout : 15000;
    const maxBufferMB  = Number.isFinite(v.avguard_maxBufferMB)  ? v.avguard_maxBufferMB  : 64;

    // Prefer filesystem path; _id can be a DB id in some contexts.
    const srcPath = fileObj.file || fileObj._id || '(unknown path)';
    const used = (args.outputFileObj ? 'outputFileObj' : 'inputFileObj');
    args.jobLog(`🔎 Inspecting ${used}: ${srcPath}`);
    args.jobLog(`🛠️ ffprobe path: ${ffprobePath} | retries: ${retryTries} | timeout: ${probeTimeout} ms`);

    const { execFileSync } = require('child_process');
    const fs = require('fs');
    const path = require('path');

    // ---------- Helpers ----------
    const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

    // Errors considered transient/lock-related on Windows/SMB
    const isTransient = (err) => {
      const msg = String(err && err.message || '').toUpperCase();
      return (
        msg.includes('EBUSY') ||
        msg.includes('EPERM') ||
        msg.includes('RESOURCE BUSY') ||
        msg.includes('PERMISSION DENIED') ||
        msg.includes('ENOENT') // brand-new file on SMB can briefly "not exist"
      );
    };

    // Try opening the file for read to ensure the share/AV released it.
    async function waitForReadable(file, tries, delayMs) {
      let attempt = 0;
      let backoff = delayMs;
      while (attempt < tries) {
        try {
          // Also check directory exists to reduce ENOENT flapping
          const dir = path.dirname(file);
          if (!fs.existsSync(dir)) throw new Error(`ENOENT: dir missing ${dir}`);
          const fd = fs.openSync(file, 'r');
          fs.closeSync(fd);
          return; // success
        } catch (e) {
          if (!isTransient(e)) throw e;
          attempt++;
          if (attempt >= tries) {
            throw e;
          }
          await sleep(backoff);
          backoff = Math.min(backoff * 2, 5000); // cap backoff growth
        }
      }
    }

    // Run ffprobe with retries/backoff
    async function ffprobeJson(probePath, file, tries, delayMs) {
      let attempt = 0;
      let backoff = delayMs;
      while (attempt < tries) {
        try {
          const out = execFileSync(
            probePath,
            [
              '-v', 'quiet',
              '-print_format', 'json',
              '-show_streams',
              '-show_format',
              file,
            ],
            {
              encoding: 'utf8',
              maxBuffer: maxBufferMB * 1024 * 1024,
              timeout: probeTimeout, // ms
            }
          );
          return JSON.parse(out);
        } catch (e) {
          // If buffer overflow, suggest increasing maxBufferMB explicitly.
          if (String(e && e.message).includes('stdout maxBuffer length exceeded')) {
            throw new Error(`ffprobe JSON exceeded ${maxBufferMB}MB; raise variables.avguard_maxBufferMB`);
          }
          if (!isTransient(e)) {
            throw e; // hard error (bad binary, invalid args, real corruption)
          }
          attempt++;
          if (attempt >= tries) {
            throw e;
          }
          await sleep(backoff);
          backoff = Math.min(backoff * 2, 5000);
        }
      }
    }

    // Parse attached_pic safely (number or string)
    const isRealVideo = (s) =>
      s?.codec_type === 'video' && !(String(s?.disposition?.attached_pic) === '1');

    // --- Primary: prefer existing ffProbeData on the object ---
    function streamsFromObj(obj) {
      const streams = obj?.ffProbeData?.streams;
      return Array.isArray(streams) && streams.length > 0 ? streams : null;
    }

    // --- MediaInfo hints (counts only) ---
    function mediaInfoHints(obj) {
      const mi = obj?.mediaInfo?.track || [];
      const miHasVideo = mi.some(t => (t['@type'] || '').toLowerCase() === 'video');
      const miHasAudio = mi.some(t => (t['@type'] || '').toLowerCase() === 'audio');
      return { miHasVideo, miHasAudio };
    }

    async function getStreamsLockAware(obj, pathToFile) {
      // 1) Already scanned?
      const fromObj = streamsFromObj(obj);
      if (fromObj) return { streams: fromObj, source: 'object' };

      // 2) Wait until readable (handles transient locks)
      try {
        await waitForReadable(pathToFile, retryTries, retryDelayMs);
      } catch (e) {
        args.jobLog(`⏳ File not readable after retries: ${e.message}`);
        // Fall through to decide based on allowSynthetic + MediaInfo hints
      }

      // 3) Try ffprobe (with retries/backoff)
      try {
        const parsed = await ffprobeJson(ffprobePath, pathToFile, retryTries, retryDelayMs);
        if (Array.isArray(parsed?.streams) && parsed.streams.length > 0) {
          args.jobLog('🛰️ Re-probed file with ffprobe (fallback).');
          return { streams: parsed.streams, source: 'ffprobe' };
        }
      } catch (e) {
        args.jobLog(`⚠️ ffprobe failed after retries: ${e.message}`);
      }

      // 4) Optional: synthetic streams based on MediaInfo counts
      const { miHasVideo, miHasAudio } = mediaInfoHints(obj);
      if (allowSynthetic && (miHasVideo || miHasAudio)) {
        args.jobLog('🧪 Using synthetic streams from MediaInfo hints (allowSynthetic=true).');
        const synthetic = [];
        if (miHasVideo) synthetic.push({ codec_type: 'video', disposition: {} });
        if (miHasAudio) synthetic.push({ codec_type: 'audio', disposition: {} });
        return { streams: synthetic, source: 'synthetic' };
      }

      return { streams: [], source: 'none' };
    }

    // ---------- Execute ----------
    const { streams, source } = await getStreamsLockAware(fileObj, srcPath);

    if (!Array.isArray(streams) || streams.length === 0) {
      args.jobLog(`❌ No streams available after probing (source=${source}).`);
      return {
        outputFileObj: fileObj,
        outputNumber: 2,
        error: 'Probe missing/empty',
      };
    }

    const hasVideo = streams.some(isRealVideo);
    const hasAudio = streams.some(s => s?.codec_type === 'audio');

    // Compare against original input to catch drop after ffmpeg block
    const inStreams = args.inputFileObj?.ffProbeData?.streams || [];
    const hadVideoIn = inStreams.some(isRealVideo);
    const hadAudioIn = inStreams.some(s => s?.codec_type === 'audio');

    const vars = {
      ...args.variables,
      avguard_used: used,
      avguard_src: srcPath,
      avguard_probeSource: source,
      avguard_hasAudio: hasAudio,
      avguard_hasVideo: hasVideo,
      avguard_inputHadAudio: hadAudioIn,
      avguard_inputHadVideo: hadVideoIn,
      avguard_audioDropped: hadAudioIn && !hasAudio,
      avguard_videoDropped: hadVideoIn && !hasVideo,
    };

    // Enforce stream presence
    if (!hasAudio && !hasVideo) {
      args.jobLog('❌ No audio AND no video streams present.');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'No A/V streams', variables: vars };
    }
    if (hadAudioIn && !hasAudio) {
      args.jobLog('❌ Missing audio stream (audio dropped since input).');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'Missing audio (dropped)', variables: vars };
    }
    if (!hadAudioIn && !hasAudio) {
      args.jobLog('❌ Missing audio stream.');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'Missing audio', variables: vars };
    }
    if (hadVideoIn && !hasVideo) {
      args.jobLog('❌ Missing video stream (video dropped since input).');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'Missing video (dropped)', variables: vars };
    }
    if (!hadVideoIn && !hasVideo) {
      args.jobLog('❌ Missing video stream.');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'Missing video', variables: vars };
    }

    // Success
    args.jobLog('✅ Audio and video streams are intact.');
    return { outputFileObj: fileObj, outputNumber: 1, variables: vars };

  } catch (err) {
    args.jobLog(`❌ Stream check crashed: ${err.message}`);
    return {
      outputFileObj: args.outputFileObj ?? args.inputFileObj,
      outputNumber: 2,
      error: 'Stream check crashed',
      variables: args.variables,
    };
  }
};

// Tdarr Flow Custom JS Plugin: Robust A/V Stream Guard (lock-aware)
// - Verifies audio/video streams on the current working file (prefers outputFileObj, else inputFileObj)
// - Retries around transient file locks (EBUSY/EPERM/ENOENT) before probing
// - Uses ffprobe with larger buffer + timeout and path overrides
// - Optional "synthetic streams" fallback via args.variables.avguard_allowSynthetic (default: false)
// - Detects dropped streams by comparing to original input
//
// ---- Runtime knobs (set in Flow variables or previous blocks) ----
// variables.avguard_allowSynthetic: boolean  (default: false)
// variables.avguard_ffprobePath:   string   (default: args.deps.ffprobePath || process.env.FFPROBE_PATH || 'ffprobe')
// variables.avguard_retryTries:    number   (default: 6)            // total attempts for lock/ffprobe
// variables.avguard_retryDelayMs:  number   (default: 300)          // initial backoff (exponential)
// variables.avguard_probeTimeout:  number   (default: 15000)        // ms
// variables.avguard_maxBufferMB:   number   (default: 64)           // ffprobe JSON max buffer
//
// Notes:
// - Place Tdarr work/cache on a local, AV-excluded path to minimize EBUSY.
// - Give each worker a unique workDir to avoid temp-file collisions.

module.exports = async (args) => {
  try {
    const fileObj = args.outputFileObj ?? args.inputFileObj;
    if (!fileObj) {
      args.jobLog('❌ No file object provided to stream-check block.');
      return {
        outputFileObj: args.outputFileObj ?? args.inputFileObj,
        outputNumber: 2,
        error: 'No file to inspect',
      };
    }

    // --- Config from variables with sane defaults ---
    const v = args.variables || {};
    const allowSynthetic = Boolean(v.avguard_allowSynthetic ?? false);
    const ffprobePath =
      v.avguard_ffprobePath ||
      args?.deps?.ffprobePath ||
      process.env.FFPROBE_PATH ||
      'ffprobe';

    const retryTries   = Number.isFinite(v.avguard_retryTries)   ? v.avguard_retryTries   : 6;
    const retryDelayMs = Number.isFinite(v.avguard_retryDelayMs) ? v.avguard_retryDelayMs : 300;
    const probeTimeout = Number.isFinite(v.avguard_probeTimeout) ? v.avguard_probeTimeout : 15000;
    const maxBufferMB  = Number.isFinite(v.avguard_maxBufferMB)  ? v.avguard_maxBufferMB  : 64;

    // Prefer filesystem path; _id can be a DB id in some contexts.
    const srcPath = fileObj.file || fileObj._id || '(unknown path)';
    const used = (args.outputFileObj ? 'outputFileObj' : 'inputFileObj');
    args.jobLog(`🔎 Inspecting ${used}: ${srcPath}`);
    args.jobLog(`🛠️ ffprobe path: ${ffprobePath} | retries: ${retryTries} | timeout: ${probeTimeout} ms`);

    const { execFileSync } = require('child_process');
    const fs = require('fs');
    const path = require('path');

    // ---------- Helpers ----------
    const sleep = (ms) => new Promise((r) => setTimeout(r, ms));

    // Errors considered transient/lock-related on Windows/SMB
    const isTransient = (err) => {
      const msg = String(err && err.message || '').toUpperCase();
      return (
        msg.includes('EBUSY') ||
        msg.includes('EPERM') ||
        msg.includes('RESOURCE BUSY') ||
        msg.includes('PERMISSION DENIED') ||
        msg.includes('ENOENT') // brand-new file on SMB can briefly "not exist"
      );
    };

    // Try opening the file for read to ensure the share/AV released it.
    async function waitForReadable(file, tries, delayMs) {
      let attempt = 0;
      let backoff = delayMs;
      while (attempt < tries) {
        try {
          // Also check directory exists to reduce ENOENT flapping
          const dir = path.dirname(file);
          if (!fs.existsSync(dir)) throw new Error(`ENOENT: dir missing ${dir}`);
          const fd = fs.openSync(file, 'r');
          fs.closeSync(fd);
          return; // success
        } catch (e) {
          if (!isTransient(e)) throw e;
          attempt++;
          if (attempt >= tries) {
            throw e;
          }
          await sleep(backoff);
          backoff = Math.min(backoff * 2, 5000); // cap backoff growth
        }
      }
    }

    // Run ffprobe with retries/backoff
    async function ffprobeJson(probePath, file, tries, delayMs) {
      let attempt = 0;
      let backoff = delayMs;
      while (attempt < tries) {
        try {
          const out = execFileSync(
            probePath,
            [
              '-v', 'quiet',
              '-print_format', 'json',
              '-show_streams',
              '-show_format',
              file,
            ],
            {
              encoding: 'utf8',
              maxBuffer: maxBufferMB * 1024 * 1024,
              timeout: probeTimeout, // ms
            }
          );
          return JSON.parse(out);
        } catch (e) {
          // If buffer overflow, suggest increasing maxBufferMB explicitly.
          if (String(e && e.message).includes('stdout maxBuffer length exceeded')) {
            throw new Error(`ffprobe JSON exceeded ${maxBufferMB}MB; raise variables.avguard_maxBufferMB`);
          }
          if (!isTransient(e)) {
            throw e; // hard error (bad binary, invalid args, real corruption)
          }
          attempt++;
          if (attempt >= tries) {
            throw e;
          }
          await sleep(backoff);
          backoff = Math.min(backoff * 2, 5000);
        }
      }
    }

    // Parse attached_pic safely (number or string)
    const isRealVideo = (s) =>
      s?.codec_type === 'video' && !(String(s?.disposition?.attached_pic) === '1');

    // --- Primary: prefer existing ffProbeData on the object ---
    function streamsFromObj(obj) {
      const streams = obj?.ffProbeData?.streams;
      return Array.isArray(streams) && streams.length > 0 ? streams : null;
    }

    // --- MediaInfo hints (counts only) ---
    function mediaInfoHints(obj) {
      const mi = obj?.mediaInfo?.track || [];
      const miHasVideo = mi.some(t => (t['@type'] || '').toLowerCase() === 'video');
      const miHasAudio = mi.some(t => (t['@type'] || '').toLowerCase() === 'audio');
      return { miHasVideo, miHasAudio };
    }

    async function getStreamsLockAware(obj, pathToFile) {
      // 1) Already scanned?
      const fromObj = streamsFromObj(obj);
      if (fromObj) return { streams: fromObj, source: 'object' };

      // 2) Wait until readable (handles transient locks)
      try {
        await waitForReadable(pathToFile, retryTries, retryDelayMs);
      } catch (e) {
        args.jobLog(`⏳ File not readable after retries: ${e.message}`);
        // Fall through to decide based on allowSynthetic + MediaInfo hints
      }

      // 3) Try ffprobe (with retries/backoff)
      try {
        const parsed = await ffprobeJson(ffprobePath, pathToFile, retryTries, retryDelayMs);
        if (Array.isArray(parsed?.streams) && parsed.streams.length > 0) {
          args.jobLog('🛰️ Re-probed file with ffprobe (fallback).');
          return { streams: parsed.streams, source: 'ffprobe' };
        }
      } catch (e) {
        args.jobLog(`⚠️ ffprobe failed after retries: ${e.message}`);
      }

      // 4) Optional: synthetic streams based on MediaInfo counts
      const { miHasVideo, miHasAudio } = mediaInfoHints(obj);
      if (allowSynthetic && (miHasVideo || miHasAudio)) {
        args.jobLog('🧪 Using synthetic streams from MediaInfo hints (allowSynthetic=true).');
        const synthetic = [];
        if (miHasVideo) synthetic.push({ codec_type: 'video', disposition: {} });
        if (miHasAudio) synthetic.push({ codec_type: 'audio', disposition: {} });
        return { streams: synthetic, source: 'synthetic' };
      }

      return { streams: [], source: 'none' };
    }

    // ---------- Execute ----------
    const { streams, source } = await getStreamsLockAware(fileObj, srcPath);

    if (!Array.isArray(streams) || streams.length === 0) {
      args.jobLog(`❌ No streams available after probing (source=${source}).`);
      return {
        outputFileObj: fileObj,
        outputNumber: 2,
        error: 'Probe missing/empty',
      };
    }

    const hasVideo = streams.some(isRealVideo);
    const hasAudio = streams.some(s => s?.codec_type === 'audio');

    // Compare against original input to catch drop after ffmpeg block
    const inStreams = args.inputFileObj?.ffProbeData?.streams || [];
    const hadVideoIn = inStreams.some(isRealVideo);
    const hadAudioIn = inStreams.some(s => s?.codec_type === 'audio');

    const vars = {
      ...args.variables,
      avguard_used: used,
      avguard_src: srcPath,
      avguard_probeSource: source,
      avguard_hasAudio: hasAudio,
      avguard_hasVideo: hasVideo,
      avguard_inputHadAudio: hadAudioIn,
      avguard_inputHadVideo: hadVideoIn,
      avguard_audioDropped: hadAudioIn && !hasAudio,
      avguard_videoDropped: hadVideoIn && !hasVideo,
    };

    // Enforce stream presence
    if (!hasAudio && !hasVideo) {
      args.jobLog('❌ No audio AND no video streams present.');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'No A/V streams', variables: vars };
    }
    if (hadAudioIn && !hasAudio) {
      args.jobLog('❌ Missing audio stream (audio dropped since input).');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'Missing audio (dropped)', variables: vars };
    }
    if (!hadAudioIn && !hasAudio) {
      args.jobLog('❌ Missing audio stream.');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'Missing audio', variables: vars };
    }
    if (hadVideoIn && !hasVideo) {
      args.jobLog('❌ Missing video stream (video dropped since input).');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'Missing video (dropped)', variables: vars };
    }
    if (!hadVideoIn && !hasVideo) {
      args.jobLog('❌ Missing video stream.');
      return { outputFileObj: fileObj, outputNumber: 2, error: 'Missing video', variables: vars };
    }

    // Success
    args.jobLog('✅ Audio and video streams are intact.');
    return { outputFileObj: fileObj, outputNumber: 1, variables: vars };

  } catch (err) {
    args.jobLog(`❌ Stream check crashed: ${err.message}`);
    return {
      outputFileObj: args.outputFileObj ?? args.inputFileObj,
      outputNumber: 2,
      error: 'Stream check crashed',
      variables: args.variables,
    };
  }
};

// Check if preprocessed and needs replacement
module.exports = (args) => {
  const wasPreprocessed = args.variables.preprocessed === true || args.variables.requiresReplacement === true;
  if (wasPreprocessed) {
    args.jobLog('File was preprocessed - forcing replacement');
    return { outputFileObj: args.inputFileObj, outputNumber: 2, variables: args.variables };
  }
  args.jobLog('File not preprocessed - no replacement needed');
  return { outputFileObj: args.inputFileObj, outputNumber: 1, variables: args.variables };
};
